module counter_4bit (clk, rst, q);
   input clk, rst;
   output [3:0] q;

   reg [3:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        q <= 4'b0000;
    end else begin
        q <= q + 1;
    end
end

endmodule
